import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Users, Briefcase, Activity, DollarSign } from "lucide-react"

interface AdminOverviewProps {
  totalUsers: number
  totalFunds: number
  totalTransactionVolume: number
  totalAUM: number
}

export function AdminOverview({ totalUsers, totalFunds, totalTransactionVolume, totalAUM }: AdminOverviewProps) {
  const formatCurrency = (value: number) => {
    const crores = value / 10000000
    return `₹${crores.toFixed(2)} Cr`
  }

  return (
    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
      <Card>
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <CardTitle className="text-sm font-medium text-gray-600">Total Users</CardTitle>
          <Users className="h-4 w-4 text-gray-400" />
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold">{totalUsers}</div>
          <p className="mt-1 text-xs text-gray-500">Registered accounts</p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <CardTitle className="text-sm font-medium text-gray-600">Active Funds</CardTitle>
          <Briefcase className="h-4 w-4 text-gray-400" />
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold">{totalFunds}</div>
          <p className="mt-1 text-xs text-gray-500">Mutual funds</p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <CardTitle className="text-sm font-medium text-gray-600">Transaction Volume</CardTitle>
          <Activity className="h-4 w-4 text-gray-400" />
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold">{formatCurrency(totalTransactionVolume)}</div>
          <p className="mt-1 text-xs text-gray-500">Total processed</p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <CardTitle className="text-sm font-medium text-gray-600">Total AUM</CardTitle>
          <DollarSign className="h-4 w-4 text-gray-400" />
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold">{formatCurrency(totalAUM)}</div>
          <p className="mt-1 text-xs text-gray-500">Assets under management</p>
        </CardContent>
      </Card>
    </div>
  )
}
