"use client"

import { useEffect, useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { LocalDB } from "@/lib/local-storage/db"

export function RecentActivity() {
  const [logs, setLogs] = useState<any[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let mounted = true

    const load = async () => {
      setLoading(true)
      try {
        const tx = await LocalDB.getAllTransactions()
        const users = await LocalDB.getAllUsers()

        // Create simple activity logs from transactions
        const activity = tx
          .slice()
          .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
          .slice(0, 10)
          .map((t) => ({
            id: t.id,
            actor: users.find((u) => u.id === t.investor_id)?.full_name || "Unknown",
            action: t.transaction_type === "buy" ? "TRANSACTION_BUY" : "TRANSACTION_SELL",
            entity_type: "transaction",
            created_at: t.created_at,
          }))

        if (mounted) setLogs(activity)
      } catch (err) {
        console.error(err)
      } finally {
        if (mounted) setLoading(false)
      }
    }

    load()
    return () => {
      mounted = false
    }
  }, [])

  const formatDate = (date: string) => {
    return new Date(date).toLocaleString("en-IN", {
      month: "short",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    })
  }

  const getActionColor = (action: string) => {
    switch (action) {
      case "TRANSACTION_BUY":
        return "bg-green-100 text-green-800"
      case "TRANSACTION_SELL":
        return "bg-blue-100 text-blue-800"
      default:
        return "bg-gray-100 text-gray-800"
    }
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Recent Activity</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="space-y-4">
          {loading ? (
            <p className="text-center text-sm text-gray-500">Loading...</p>
          ) : logs && logs.length > 0 ? (
            logs.map((log) => (
              <div key={log.id} className="rounded-lg border p-3">
                <div className="mb-2 flex items-start justify-between">
                  <p className="text-sm font-medium">{log.actor}</p>
                  <Badge className={getActionColor(log.action)}>{log.action}</Badge>
                </div>
                <p className="text-xs text-gray-600">{log.entity_type}</p>
                <p className="mt-1 text-xs text-gray-400">{formatDate(log.created_at)}</p>
              </div>
            ))
          ) : (
            <p className="text-center text-sm text-gray-500">No recent activity</p>
          )}
        </div>
      </CardContent>
    </Card>
  )
}
